            package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings a specified host a user-defined number of times 
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	var cmd *exec.Cmd

	// Handle OS-specific arguments for the ping command
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command
	out, err := cmd.CombinedOutput()

	// Use a regular expression to find all latency times in the output.
	// This works across Windows, Linux, and macOS by matching "time=XXms" or "time<XXms"
	re := regexp.MustCompile(`(?i)time[=<]\s*([0-9.]+)`)
	matches := re.FindAllStringSubmatch(string(out), -1)

	// If no matches were found, it means the ping failed completely (e.g., unknown host, 100% packet loss)
	if len(matches) == 0 {
		if err != nil {
			return 0, fmt.Errorf("ping failed: %w, output: %s", err, string(out))
		}
		return 0, fmt.Errorf("could not parse ping output, no time data found")
	}

	var totalLatency float64
	var validCount int

	// Parse the captured times and calculate the sum
	for _, match := range matches {
		if len(match) > 1 {
			val, parseErr := strconv.ParseFloat(match[1], 64)
			if parseErr == nil {
				totalLatency += val
				validCount++
			}
		}
	}

	if validCount == 0 {
		return 0, fmt.Errorf("failed to parse any valid latency values from output")
	}

	// Calculate and return the average latency
	return totalLatency / float64(validCount), nil
}

func main() {
	host := "8.8.8.8" // Google's public DNS
	count := 4

	fmt.Printf("Measuring network latency to %s (%d attempts)...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average Latency: %.2f ms\n", avgLatency)
}

