// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("count must be greater than zero")
	}

	var cmd *exec.Cmd
	// Use the appropriate flag for the number of pings based on the operating system
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the ping command and capture the combined standard output and error
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w (output: %s)", err, string(output))
	}

	// Regular expression to match the time=X.X ms or time<1ms part of the ping output.
	// This approach is cross-platform as it captures individual ping times rather than
	// relying on OS-specific summary formats.
	re := regexp.MustCompile(`time[=<]([0-9]*\.?[0-9]+)`)
	matches := re.FindAllStringSubmatch(string(output), -1)

	if len(matches) == 0 {
		return 0, errors.New("failed to parse latency from ping output")
	}

	var totalLatency float64
	var validPings int

	// Calculate the total latency from the parsed values
	for _, match := range matches {
		if len(match) > 1 {
			latency, err := strconv.ParseFloat(match[1], 64)
			if err == nil {
				totalLatency += latency
				validPings++
			}
		}
	}

	if validPings == 0 {
		return 0, errors.New("no valid latency values found")
	}

	// Return the computed average latency
	return totalLatency / float64(validPings), nil
}

func main() {
	host := "8.8.8.8" // Google's public DNS server
	count := 4

	fmt.Printf("Pinging %s %d times to measure latency...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average Latency: %.2f ms\n", avgLatency)
}

