// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	var cmd *exec.Cmd

	// Handle cross-platform differences for the ping command
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Force English output on Unix-like systems to make parsing reliable
	cmd.Env = append(os.Environ(), "LANG=C", "LC_ALL=C")

	// Execute the command
	out, err := cmd.CombinedOutput()

	// Use a regular expression to extract latency times from the output.
	// This regex matches strings like "time=14.2", "time=14", or "time<1" 
	// which are standard across Linux, macOS, and Windows ping outputs.
	re := regexp.MustCompile(`(?i)time[=<]([0-9.]+)`)
	matches := re.FindAllStringSubmatch(string(out), -1)

	// If no matches are found, the ping likely failed or the host is unreachable
	if len(matches) == 0 {
		if err != nil {
			return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(out))
		}
		return 0, fmt.Errorf("could not parse any latency values from ping output: %s", string(out))
	}

	var totalLatency float64
	var validCount int

	// Iterate through all matched latency values, parse them, and calculate the sum
	for _, match := range matches {
		if len(match) > 1 {
			val, parseErr := strconv.ParseFloat(match[1], 64)
			if parseErr == nil {
				totalLatency += val
				validCount++
			}
		}
	}

	if validCount == 0 {
		return 0, fmt.Errorf("found time values but failed to parse them as floats")
	}

	// Calculate and return the average
	averageLatency := totalLatency / float64(validCount)
	return averageLatency, nil
}

func main() {
	// Example usage
	host := "8.8.8.8" // Google's public DNS
	count := 4

	fmt.Printf("Pinging %s %d times...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average Latency: %.2f ms\n", avgLatency)
}

