	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("count must be greater than 0")
	}

	var cmd *exec.Cmd
	// Windows uses "-n" for the count of echo requests, whereas Unix-like systems use "-c"
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	out, err := cmd.CombinedOutput()
	output := string(out)

	// We parse the individual ping response lines instead of the summary block.
	// This makes the parsing OS and locale independent.
	// Matches patterns like "time=14.2 ms", "time=12ms", or "time<1ms"
	re := regexp.MustCompile(`(?i)time[=<]\s*([0-9.]+)\s*ms`)
	matches := re.FindAllStringSubmatch(output, -1)

	// If no valid time match is found, either the host is unreachable or the command failed.
	if len(matches) == 0 {
		if err != nil {
			return 0, fmt.Errorf("ping failed: %w, output: %s", err, output)
		}
		return 0, fmt.Errorf("could not parse ping output for latency, output: %s", output)
	}

	var total float64
	for _, match := range matches {
		val, parseErr := strconv.ParseFloat(match[1], 64)
		if parseErr != nil {
			return 0, fmt.Errorf("failed to parse latency value '%s': %w", match[1], parseErr)
		}
		total += val
	}

	// Calculate the average latency based on successful replies received
	avgLatency := total / float64(len(matches))
	return avgLatency, nil
}

func main() {
	// Configuration parameters
	host := "8.8.8.8" // Target host (Google's Public DNS)
	count := 4        // Number of ping attempts

	fmt.Printf("Pinging %s %d times...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

