// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	var cmd *exec.Cmd
	// The ping command uses different flags for the number of requests depending on the OS.
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command and capture the output.
	// We use CombinedOutput to capture both stdout and stderr.
	out, err := cmd.CombinedOutput()

	// Use a regular expression to find the latency values from the individual ping responses.
	// This approach is more robust across different OSes and locales than parsing the summary line.
	// It matches "time=X.X" (Linux/macOS/Windows) or "time<X" (Windows <1ms).
	re := regexp.MustCompile(`(?i)time[=<]([0-9.]+)`)
	matches := re.FindAllStringSubmatch(string(out), -1)

	// If no latency data could be parsed, return an error.
	if len(matches) == 0 {
		if err != nil {
			return 0, fmt.Errorf("ping failed: %v, output: %s", err, string(out))
		}
		return 0, fmt.Errorf("no latency data found in ping output: %s", string(out))
	}

	var total float64
	validCount := 0

	// Iterate over all matched latency values, convert to float, and sum them up.
	for _, match := range matches {
		val, parseErr := strconv.ParseFloat(match[1], 64)
		if parseErr == nil {
			total += val
			validCount++
		}
	}

	if validCount == 0 {
		return 0, fmt.Errorf("failed to parse latency values from output")
	}

	// Calculate and return the average latency.
	return total / float64(validCount), nil
}

func main() {
	// Example usage
	host := "8.8.8.8" // Google's public DNS
	count := 4

	fmt.Printf("Pinging %s %d times...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average Latency: %.2f ms\n", avgLatency)
}

