            package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	var cmd *exec.Cmd
	countStr := strconv.Itoa(count)

	// Handle cross-platform differences in the ping command
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", countStr, host)
	} else {
		// Unix-like systems (Linux, macOS, etc.)
		cmd = exec.Command("ping", "-c", countStr, host)
	}

	// Execute the command and capture both stdout and stderr
	output, err := cmd.CombinedOutput()

	// Regular expression to extract the time from individual ping reply lines.
	// This avoids parsing the highly OS-dependent and localized summary lines.
	// Matches formats like "time=14.2 ms", "time=14ms", "time<1ms"
	re := regexp.MustCompile(`(?i)time[=<]([0-9]+(?:\.[0-9]+)?)\s*ms`)
	matches := re.FindAllSubmatch(output, -1)

	// If no successful ping replies were parsed, return an error
	if len(matches) == 0 {
		if err != nil {
			return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
		}
		return 0, fmt.Errorf("could not parse ping output, or host unreachable. Output: %s", string(output))
	}

	var totalLatency float64
	var successfulPings int

	for _, match := range matches {
		latencyStr := string(match[1])
		latency, parseErr := strconv.ParseFloat(latencyStr, 64)
		if parseErr != nil {
			continue
		}
		totalLatency += latency
		successfulPings++
	}

	if successfulPings == 0 {
		return 0, fmt.Errorf("failed to calculate latency from parsed output")
	}

	// Calculate and return the average latency
	return totalLatency / float64(successfulPings), nil
}

func main() {
	host := "8.8.8.8" // Google Public DNS
	count := 4

	fmt.Printf("Pinging %s %d times...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average Latency to %s: %.2f ms\n", host, avgLatency)
}

