package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	var cmd *exec.Cmd

	// The ping command arguments differ between Windows and Unix-like systems.
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command and capture the output.
	output, err := cmd.CombinedOutput()

	// We use a regular expression to extract the time from individual ping replies.
	// This works across different OS ping implementations:
	// Linux/macOS typically outputs: "... time=14.2 ms"
	// Windows typically outputs: "... time=14ms" or "... time<1ms"
	re := regexp.MustCompile(`(?i)time[=<]\s*([0-9.]+)`)
	matches := re.FindAllStringSubmatch(string(output), -1)

	// If no times were found, the ping likely failed completely.
	if len(matches) == 0 {
		if err != nil {
			return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
		}
		return 0, fmt.Errorf("could not parse latency from ping output: %s", string(output))
	}

	var totalLatency float64
	var validCount int

	// Parse the extracted time values and calculate the sum.
	for _, match := range matches {
		if len(match) > 1 {
			val, parseErr := strconv.ParseFloat(match[1], 64)
			if parseErr == nil {
				totalLatency += val
				validCount++
			}
		}
	}

	if validCount == 0 {
		return 0, fmt.Errorf("could not parse any valid latency values")
	}

	// Return the average latency.
	return totalLatency / float64(validCount), nil
}

func main() {
	// Example usage
	host := "8.8.8.8"
	count := 4

	fmt.Printf("Pinging %s %d times...\n", host, count)
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

