	cmd.Stdout = &out
	// Capture stderr as well, as some implementations might write errors there.
	cmd.Stderr = &out

	err := cmd.Run()
	output := out.String()

	var avgLatency float64
	var parseErr error

	if runtime.GOOS == "windows" {
