		reAvg := regexp.MustCompile(`(?i)Average.*?=\s*(\d+)`)
		matchAvg := reAvg.FindStringSubmatch(output)
		if len(matchAvg) > 1 {
			avgLatency, parseErr = strconv.ParseFloat(matchAvg[1], 64)
			if parseErr == nil {
				return avgLatency, nil
			}
		}

		// Fallback: match the last occurrence of "= X ms" which is typically the average in the summary.
		re := regexp.MustCompile(`=\s*(\d+)\s*ms`)
		matches := re.FindAllStringSubmatch(output, -1)
		if len(matches) > 0 {
			lastMatch := matches[len(matches)-1]
			avgLatency, parseErr = strconv.ParseFloat(lastMatch[1], 64)
			if parseErr == nil {
