// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("count must be greater than 0")
	}

	var cmd *exec.Cmd
	countStr := strconv.Itoa(count)

	// Windows uses "-n" for count, Unix-like systems use "-c"
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", countStr, host)
	} else {
		cmd = exec.Command("ping", "-c", countStr, host)
	}

	// Run the command and get the output
	outputBytes, err := cmd.CombinedOutput()
	output := string(outputBytes)

	// Regular expression to extract the time from the ping output lines.
	// It matches formats like "time=14.2", "time=14", or "time<1" and extracts the numeric value.
	re := regexp.MustCompile(`(?i)time\s*[=<]\s*([0-9]+(?:\.[0-9]+)?)`)
	matches := re.FindAllStringSubmatch(output, -1)

	// If no matches were found, the ping likely failed or timed out completely
	if len(matches) == 0 {
		if err != nil {
			return 0, fmt.Errorf("ping failed: %w, output: %s", err, strings.TrimSpace(output))
		}
		return 0, errors.New("could not parse ping output or no responses received")
	}

	var totalLatency float64
	var validMatches int

	// Iterate over all matched latency values, parse them, and sum them up
	for _, match := range matches {
		if len(match) > 1 {
			latency, parseErr := strconv.ParseFloat(match[1], 64)
			if parseErr == nil {
				totalLatency += latency
				validMatches++
			}
		}
	}

	if validMatches == 0 {
		return 0, errors.New("could not parse any valid latency values from the output")
	}

	// Calculate and return the average
	averageLatency := totalLatency / float64(validMatches)
	return averageLatency, nil
}

func main() {
	host := "8.8.8.8" // Google's public DNS
	count := 4

	fmt.Printf("Measuring network latency to %s (%d attempts)...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Success! Average latency: %.2f ms\n", avgLatency)
}

