// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	var cmd *exec.Cmd

	// Configure the ping command based on the operating system
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var out bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &out

	// Execute the ping command
	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping execution failed: %v, output: %s", err, out.String())
	}

	output := out.String()

	// Parse the output to extract the average latency
	if runtime.GOOS == "windows" {
		// Windows ping output format typically ends with:
		// Minimum = Xms, Maximum = Yms, Average = Zms
		// We match all occurrences of "= <number>ms" and take the last one (Average)
		re := regexp.MustCompile(`=\s*([0-9.]+)\s*ms`)
		matches := re.FindAllStringSubmatch(output, -1)
		if len(matches) == 0 {
			return 0, fmt.Errorf("could not parse average latency from output: %s", output)
		}

		// The last match in the summary is the average latency
		avgStr := matches[len(matches)-1][1]
		return strconv.ParseFloat(avgStr, 64)
	}

	// Unix-like systems (Linux, macOS, BSD)
	// Linux typically outputs: rtt min/avg/max/mdev = 1.234/5.678/9.012/3.456 ms
	// macOS typically outputs: round-trip min/avg/max/stddev = 1.234/5.678/9.012/3.456 ms
	// Alpine/Busybox outputs: round-trip min/avg/max = 1.2/3.4/5.6 ms
	// This regex captures the middle value (avg) out of the min/avg/max sequence
	re := regexp.MustCompile(`=\s*[0-9.]+/([0-9.]+)/[0-9.]+`)
	matches := re.FindStringSubmatch(output)
	if len(matches) < 2 {
		return 0, fmt.Errorf("could not parse average latency from output: %s", output)
	}

	return strconv.ParseFloat(matches[1], 64)
}

func main() {
	host := "8.8.8.8"
	count := 4

	fmt.Printf("Pinging %s %d times...\n", host, count)

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average Latency to %s: %.2f ms\n", host, avg)
}

