import (
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings a specified host a given number of times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	var cmd *exec.Cmd

	// Configure the ping command based on the operating system
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
		// Force standard POSIX locale to ensure predictable output parsing on Unix-like systems
		cmd.Env = append(os.Environ(), "LC_ALL=C")
	}

	// Execute the command and capture the output
	outputBytes, err := cmd.CombinedOutput()
	output := string(outputBytes)

	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v, output: %s", err, output)
	}

	// Try Unix-like format (Linux/macOS)
	// Example: rtt min/avg/max/mdev = 1.234/5.678/9.012/3.456 ms
	reUnix := regexp.MustCompile(`(?:min/avg/max[^=]*=\s*[\d.]+/([\d.]+)/[\d.]+)`)
	if matches := reUnix.FindStringSubmatch(output); len(matches) >= 2 {
		return strconv.ParseFloat(matches[1], 64)
	}

	// Try Windows format (English)
	// Example: Minimum = 1ms, Maximum = 2ms, Average = 12ms
	reWin := regexp.MustCompile(`Average\s*=\s*([\d.]+)\s*ms`)
	if matches := reWin.FindStringSubmatch(output); len(matches) >= 2 {
		return strconv.ParseFloat(matches[1], 64)
	}

	// Try Windows format (Non-English fallback)
	// Matches the last occurrence of "= <number>ms" which is typically the average
	reWinFallback := regexp.MustCompile(`=\s*([\d.]+)\s*ms`)
	if matches := reWinFallback.FindAllStringSubmatch(output, -1); len(matches) > 0 {
		return strconv.ParseFloat(matches[len(matches)-1][1], 64)
	}

	return 0, fmt.Errorf("average latency not found in output:\n%s", output)
}

func main() {
	// Configuration
	host := "8.8.8.8" // Google's public DNS server
	count := 4        // Number of ping attempts

	fmt.Printf("Pinging %s %d times...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average Latency to %s: %.2f ms\n", host, avgLatency)
}

