import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// latencyRegex matches the time=X.X or time<X format in ping output across different OSes.
var latencyRegex = regexp.MustCompile(`(?i)time[=<]\s*([0-9.]+)`)

// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("count must be greater than 0")
	}

	var cmd *exec.Cmd

	// Handle OS-specific arguments for the ping command
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command and capture the output
	output, err := cmd.CombinedOutput()

	// Extract latency values using the regular expression
	matches := latencyRegex.FindAllStringSubmatch(string(output), -1)

	// If no matches were found, it means the ping failed entirely or output is unrecognized
	if len(matches) == 0 {
		if err != nil {
			return 0, fmt.Errorf("ping execution failed: %w, output: %s", err, string(output))
		}
		return 0, errors.New("could not parse latency from ping output")
	}

	var totalLatency float64
	var validCount int

	// Parse the extracted string values into floats and calculate the total
	for _, match := range matches {
		if len(match) > 1 {
			val, parseErr := strconv.ParseFloat(match[1], 64)
			if parseErr == nil {
				totalLatency += val
				validCount++
			}
		}
	}

	if validCount == 0 {
		return 0, errors.New("no valid latency values found in the output")
	}

	// Calculate and return the average
	return totalLatency / float64(validCount), nil
}

func main() {
	host := "8.8.8.8" // Google's public DNS
	count := 4

	fmt.Printf("Pinging %s %d times...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average Latency to %s: %.2f ms\n", host, avgLatency)
}

